### Toggle Item in Cart

```javascript
async function toggleItem(packageId) {
  if (next.hasItemInCart({ packageId })) {
    await next.removeItem({ packageId });
  } else {
    await next.addItem({ packageId });
  }
}

// Usage
await toggleItem(123);
