### Verify Event Firing

```javascript
// Check if events are being sent
window.nextReady.push(function() {
  const events = [];

  // Capture all analytics events
  next.on('analytics:event', function(event) {
    events.push({
      event: event.event,
      timestamp: Date.now(),
      data: event
    });
