### Google Analytics

```javascript
next.on('cart:item-added', (data) => {
  if (typeof gtag !== 'undefined') {
    gtag('event', 'add_to_cart', {
      value: data.item.price,
      currency: 'USD',
      items: [data.item]
    });
  }
});

next.on('order:completed', (order) => {
